1	'use strict';
2	// facts/identity.js - THE single door for the IDENTITY fact (Constitution Rule 1).
3	//
4	// This module is the only producer of display_name, legal_name, company_number,
5	// registered_office and slug. It is a pure function over an EvidenceBundle: it never
6	// fetches the network, never queries a register, never guesses. Register data arrives
7	// pre-fetched on bundle.registers; page data arrives on bundle.corpus.
8	//
9	// THE LADDER (highest confidence first; the winning rung is recorded in evidence):
10	//   1. registers.companiesHouse row, corroborated by an on-page identifier
11	//      (the company number appearing in the corpus, or the register name matching an
12	//      on-page candidate). Confidence 'register'.
13	//   2. schema.org Organization / LegalService legalName or name from page jsonLd.
14	//   3. ogSiteName.
15	//   4. footer identity block ("(c) X Ltd", "X LLP is authorised and regulated by",
16	//      company number with context words).
17	//   5. <title>, split on the site's own separator, marketing tails removed.
18	//   6. domain stem - always-clean last resort, confidence 'weak'.
19	// Two or more independent on-page rungs agreeing -> 'corroborated'. A single source
20	// -> 'weak'. Nothing safe -> 'abstain'. Abstention is a first-class outcome: a missing
21	// field is fine, a wrong one ends the company (caution C-001, C-002, C-003).
22	//
23	// REJECTION (a rejected candidate falls through; it never poisons the result):
24	//   - generic page furniture (Office, Home, Contact, About, Menu, Price List, Welcome...)
25	//   - marketing headlines longer than 6 words
26	//   - strings carrying HTML entity residue (&amp; / &#x27; ...) - these are scrape
27	//     artefacts, never names; they produced the live "luxury-aesthetic-clinic-for-
28	//     radiant-skin-amp-body" and "price-list" slugs (caution C-003)
29	//   - candidates sharing no token with the domain, unless register-corroborated (C-002)
30	//
31	// The slug derives ONLY from the resolved display_name, never from a page title.
32	//
33	// Vocabulary: word lists come from facts/vocabulary.js (one door for vocabulary).
34	// If that module is absent at load time (parallel P1 build), a frozen inline fallback
35	// is used, the source is recorded in VOCABULARY_SOURCE and in every result's notes,
36	// and the loader throws loudly if vocabulary.js is present but missing a required
37	// export. Nothing degrades silently.
38	
39	// ---------------------------------------------------------------------------------
40	// Vocabulary (one door; guarded loader with recorded fallback)
41	// ---------------------------------------------------------------------------------
42	const REQUIRED_VOCABULARY_EXPORTS = [
43	  'GENERIC_PAGE_TERMS',
44	  'LEGAL_ENTITY_SUFFIXES',
45	  'MARKETING_TAIL_TERMS',
46	  'REGULATED_BY_PHRASES',
47	  'COMPANY_NUMBER_CONTEXT_TERMS',
48	  'PUBLIC_SUFFIX_SECOND_LEVEL',
49	  'TITLE_SMALL_WORDS',
50	  'KEEP_UPPERCASE_TOKENS',
51	];
52	
53	const FALLBACK_VOCABULARY = Object.freeze({
54	  GENERIC_PAGE_TERMS: Object.freeze([
55	    'home', 'homepage', 'home page', 'welcome', 'index', 'untitled', 'site', 'website',
56	    'contact', 'contact us', 'about', 'about us', 'menu', 'blog', 'news', 'our team',
57	    'team', 'people', 'careers', 'jobs', 'services', 'our services', 'office', 'offices',
58	    'branch', 'branches', 'location', 'locations', 'price list', 'prices', 'pricing',
59	    'fees', 'faq', 'faqs', 'gallery', 'testimonials', 'reviews', 'book now',
60	    'book online', 'shop', 'store', 'search', 'privacy policy', 'terms', 'cookies',
61	  ]),
62	  LEGAL_ENTITY_SUFFIXES: Object.freeze([
63	    'ltd', 'limited', 'llp', 'plc', 'lp', 'llc', 'inc', 'incorporated', 'cic', 'cio',
64	    'company', 'co', 'partnership', 'pllc', 'gmbh', 'sarl', 'bv', 'pty',
65	  ]),
66	  MARKETING_TAIL_TERMS: Object.freeze([
67	    'solicitors', 'lawyers', 'law firm', 'barristers', 'accountants', 'dentists',
68	    'clinic', 'specialists', 'experts', 'consultants', 'advisors', 'advisers',
69	    'official site', 'official website', 'top', 'leading', 'best', 'luxury', 'premier',
70	    'trusted', 'award-winning', 'award winning', 'no.1', 'no 1', 'number one',
71	  ]),
72	  REGULATED_BY_PHRASES: Object.freeze([
73	    'authorised and regulated by', 'authorized and regulated by', 'regulated by',
74	    'authorised by', 'licensed by', 'licenced by', 'registered with',
75	  ]),
76	  COMPANY_NUMBER_CONTEXT_TERMS: Object.freeze([
77	    'company number', 'company no', 'company registration', 'registered number',
78	    'registration number', 'registered in england', 'registered in scotland',
79	    'registered in wales', 'registered in northern ireland', 'companies house',
80	    'registered office', 'company reg',
81	  ]),
82	  PUBLIC_SUFFIX_SECOND_LEVEL: Object.freeze([
83	    'co.uk', 'org.uk', 'me.uk', 'ltd.uk', 'plc.uk', 'net.uk', 'sch.uk', 'nhs.uk',
84	    'gov.uk', 'ac.uk', 'com.au', 'co.nz', 'co.za', 'com.sg', 'co.ae', 'com.sa', 'co.in',
85	  ]),
86	  TITLE_SMALL_WORDS: Object.freeze([
87	    'and', 'of', 'the', 'for', 'in', 'on', 'at', 'to', 'a', 'an', 'by', '&',
88	  ]),
89	  KEEP_UPPERCASE_TOKENS: Object.freeze([
90	    'UK', 'USA', 'US', 'UAE', 'LLP', 'LLC', 'PLC', 'LTD', 'NHS', 'IT', 'HR', 'PR', 'AI',
91	    'BDO', 'KPMG', 'PWC', 'EY',
92	  ]),
93	});
94	
95	function loadVocabulary() {
96	  let mod = null;
97	  try {
98	    mod = require('./vocabulary');
99	  } catch (err) {
100	    if (err && err.code === 'MODULE_NOT_FOUND' && String(err.message).indexOf('vocabulary') !== -1) {
101	      // Typed, recorded absence (never silent): facts/vocabulary.js has not landed in
102	      // this working tree yet. Use the frozen fallback and say so on every result.
103	      return { source: 'inline-fallback', lists: FALLBACK_VOCABULARY };
104	    }
105	    // A present-but-broken vocabulary module must block, never degrade (Rule 4).
106	    throw err;
107	  }
108	  const missing = REQUIRED_VOCABULARY_EXPORTS.filter(
109	    (k) => !Array.isArray(mod[k]) || mod[k].length === 0
110	  );
111	  if (missing.length) {
112	    throw new Error(
113	      'facts/identity.js: facts/vocabulary.js is present but is missing required exports: '
114	      + missing.join(', ')
115	      + '. Extend the vocabulary module (one door for word lists); do not inline strings here.'
116	    );
117	  }
118	  const lists = {};
119	  for (const k of REQUIRED_VOCABULARY_EXPORTS) {
120	    lists[k] = Object.freeze(mod[k].map((s) => String(s)));
121	  }
122	  return { source: 'facts/vocabulary.js', lists: Object.freeze(lists) };
123	}
124	
125	const VOCABULARY = loadVocabulary();
126	const V = VOCABULARY.lists;
127	const VOCABULARY_SOURCE = VOCABULARY.source;
128	
129	const CONFIDENCE = Object.freeze({
130	  REGISTER: 'register',
131	  CORROBORATED: 'corroborated',
132	  WEAK: 'weak',
133	  ABSTAIN: 'abstain',
134	});
135	
136	// ---------------------------------------------------------------------------------
137	// Small pure helpers
138	// ---------------------------------------------------------------------------------
139	function tidy(s) {
140	  return String(s == null ? '' : s).replace(/\s+/g, ' ').trim();
141	}
142	
143	// Entity residue means the string was scraped, not authored: it is never a name.
144	// We reject rather than decode (decoding is how "amp" reached a live slug).
145	const ENTITY_RX = /&(?:#\d{1,7}|#x[0-9a-f]{1,6}|[a-z][a-z0-9]{1,31});/i;
146	function hasEntityResidue(s) {
147	  return ENTITY_RX.test(String(s || ''));
148	}
149	
150	function wordCount(s) {
151	  return tidy(s).split(/\s+/).filter(Boolean).length;
152	}
153	
154	const PUB2 = new Set(V.PUBLIC_SUFFIX_SECOND_LEVEL.map((x) => x.toLowerCase()));
155	function domainStem(domain) {
156	  let d = String(domain || '').toLowerCase().trim()
157	    .replace(/^https?:\/\//, '').replace(/^www\./, '')
158	    .split('/')[0].split(':')[0];
159	  if (!d) return '';
160	  const parts = d.split('.').filter(Boolean);
161	  if (parts.length <= 1) return parts[0] || '';
162	  if (parts.length >= 3 && PUB2.has(parts.slice(-2).join('.'))) return parts[parts.length - 3];
163	  return parts[parts.length - 2];
164	}
165	
166	const SMALL = new Set(V.TITLE_SMALL_WORDS.map((x) => x.toLowerCase()));
167	const KEEP_UPPER = new Set(V.KEEP_UPPERCASE_TOKENS.map((x) => x.toUpperCase()));
168	function titleCase(s) {
169	  return tidy(s).split(/\s+/).filter(Boolean).map((w, i) => {
170	    const bare = w.replace(/[^A-Za-z]/g, '');
171	    if (!bare) return w;
172	    if (KEEP_UPPER.has(bare.toUpperCase())) return w.toUpperCase();
173	    const lw = w.toLowerCase();
174	    if (i > 0 && SMALL.has(lw)) return lw;
175	    return lw.charAt(0).toUpperCase() + lw.slice(1);
176	  }).join(' ');
177	}
178	
179	function compact(s) {
180	  return String(s || '').toLowerCase().replace(/&/g, 'and').replace(/[^a-z0-9]/g, '');
181	}
182	
183	const SUFFIX_BODY = '\\b(?:' + V.LEGAL_ENTITY_SUFFIXES.map((x) => x.replace(/[.*+?^${}()|[\]\\]/g, '\\$&')).join('|') + ')\\b\\.?';
184	const SUFFIX_RX = new RegExp(SUFFIX_BODY, 'gi');
185	const SUFFIX_TEST_RX = new RegExp(SUFFIX_BODY, 'i'); // stateless .test()
186	function stripLegalSuffixes(s) {
187	  return tidy(String(s || '').replace(SUFFIX_RX, ' '));
188	}
189	
190	// Normalised comparison key for name agreement across sources and registers.
191	function normName(s) {
192	  return compact(stripLegalSuffixes(String(s || '').replace(/&/g, ' and ')));
193	}
194	
195	function nameTokens(s) {
196	  return String(s || '').toLowerCase().replace(/&/g, ' and ')
197	    .split(/[^a-z0-9]+/).filter((t) => t.length >= 4);
198	}
199	function initialsOf(s) {
200	  return String(s || '').split(/[^A-Za-z0-9]+/).filter(Boolean).map((w) => w[0]).join('').toLowerCase();
201	}
202	
203	// A candidate must be tied to the domain: shares a token of 4+ chars with the stem,
204	// or the compacted forms contain one another (short real names: "BDO" / bdo.co.uk),
205	// or its initials are the stem (acronym sites). Register-corroborated names are exempt.
206	function sharesTokenWithDomain(candidate, domain) {
207	  const stem = compact(domainStem(domain));
208	  if (!stem) return true; // no domain to check against -> do not reject on this rule
209	  const cand = compact(stripLegalSuffixes(candidate));
210	  if (!cand) return false;
211	  if (stem.includes(cand) || cand.includes(stem)) return true;
212	  if (cand.length >= 3 && initialsOf(candidate) === stem) return true;
213	  return nameTokens(stripLegalSuffixes(candidate)).some((t) => stem.includes(t));
214	}
215	
216	const GENERIC_TERMS = new Set(
217	  V.GENERIC_PAGE_TERMS.concat(V.MARKETING_TAIL_TERMS).map((x) => x.toLowerCase())
218	);
219	function isGenericTerm(s) {
220	  let t = tidy(s).toLowerCase().replace(/^(?:the|our|my)\s+/, '');
221	  t = t.replace(/\s+/g, ' ');
222	  if (GENERIC_TERMS.has(t)) return true;
223	  // "<word> office" / "<word> branch" is page furniture, not a firm (the "Bristol
224	  // Office" live defect, caution C-002).
225	  if (/^[a-z]+\s+(?:office|branch)$/.test(t)) return true;
226	  return false;
227	}
228	
229	// Starts with a superlative marketing opener ("Top London Law Firm", "Luxury ...").
230	const MARKETING_OPENER_RX = new RegExp(
231	  '^(?:' + V.MARKETING_TAIL_TERMS
232	    .filter((x) => x.split(' ').length <= 2)
233	    .map((x) => x.replace(/[.*+?^${}()|[\]\\]/g, '\\$&')).join('|') + ')\\b',
234	  'i'
235	);
236	
237	const MAX_DISPLAY_NAME_WORDS = 6;
238	
239	// null when the candidate is acceptable, else the reason it was rejected.
240	function rejectReason(candidate, domain, opts) {
241	  const fromRegister = Boolean(opts && opts.fromRegister);
242	  const v = tidy(candidate);
243	  if (!v) return 'empty';
244	  if (v.length < 2) return 'too_short';
245	  if (v.length > 120) return 'too_long';
246	  if (hasEntityResidue(v)) return 'html_entity_residue';
247	  if (!fromRegister) {
248	    if (isGenericTerm(v)) return 'generic_page_furniture';
249	    if (wordCount(v) > MAX_DISPLAY_NAME_WORDS) return 'marketing_headline_too_long';
250	    if (!sharesTokenWithDomain(v, domain)) return 'no_token_shared_with_domain';
251	  }
252	  return null;
253	}
254	
255	// ---------------------------------------------------------------------------------
256	// Extraction from the EvidenceBundle (all pure; jsonLd arrives already parsed)
257	// ---------------------------------------------------------------------------------
258	const ORG_TYPES = new Set([
259	  'organization', 'organisation', 'legalservice', 'localbusiness', 'corporation',
260	  'professionalservice', 'attorney', 'accountingservice', 'financialservice',
261	  'medicalbusiness', 'medicalorganization', 'dentist', 'physician',
262	  'realestateagent', 'insuranceagency', 'ngo', 'educationalorganization',
263	]);
264	
265	function walkJsonLd(node, out, depth) {
266	  if (!node || depth > 6) return;
267	  if (Array.isArray(node)) {
268	    for (const n of node) walkJsonLd(n, out, depth + 1);
269	    return;
270	  }
271	  if (typeof node !== 'object') return;
272	  if (Array.isArray(node['@graph'])) walkJsonLd(node['@graph'], out, depth + 1);
273	  const rawType = node['@type'];
274	  const types = (Array.isArray(rawType) ? rawType : [rawType])
275	    .filter(Boolean)
276	    .map((t) => String(t).toLowerCase().replace(/^https?:\/\/schema\.org\//, ''));
277	  if (types.some((t) => ORG_TYPES.has(t))) {
278	    const legal = typeof node.legalName === 'string' ? tidy(node.legalName) : '';
279	    const nm = typeof node.name === 'string' ? tidy(node.name)
280	      : (node.name && typeof node.name['@value'] === 'string' ? tidy(node.name['@value']) : '');
281	    if (legal || nm) out.push({ name: legal || nm, legalName: legal || null });
282	  }
283	  for (const k of ['publisher', 'provider', 'parentOrganization', 'author', 'about', 'mainEntity', 'brand']) {
284	    if (node[k] && typeof node[k] === 'object') walkJsonLd(node[k], out, depth + 1);
285	  }
286	}
287	
288	function collectJsonLdOrgs(pages) {
289	  const out = [];
290	  for (const p of pages) {
291	    const found = [];
292	    for (const block of (Array.isArray(p.jsonLd) ? p.jsonLd : [])) {
293	      walkJsonLd(block, found, 0);
294	    }
295	    for (const f of found) out.push({ name: f.name, legalName: f.legalName, url: p.url || null });
296	  }
297	  return out;
298	}
299	
300	// The site's own separator, then generic and marketing segments removed. Segments
301	// tied to the domain are preferred: that is the firm's name, not the strapline.
302	const TITLE_SEPARATOR_RX = /\s*[|–—·•:]\s*|\s+-\s+/;
303	function titleCandidates(title, domain) {
304	  const t = tidy(title);
305	  if (!t) return [];
306	  const segs = t.split(TITLE_SEPARATOR_RX).map((s) => tidy(s)).filter(Boolean);
307	  const pool = segs.length ? segs : [t];
308	  const cleaned = pool
309	    .map((s) => tidy(s.replace(/^(?:home|welcome(?:\s+to)?)\s*[:|-]?\s*/i, '')))
310	    .filter(Boolean)
311	    .filter((s) => !(MARKETING_OPENER_RX.test(s) && pool.length > 1));
312	  const tied = cleaned.filter((s) => sharesTokenWithDomain(s, domain) && !isGenericTerm(s));
313	  return tied.concat(cleaned.filter((s) => tied.indexOf(s) === -1));
314	}
315	
316	// Footer identity block: "(c) 2026 X Ltd", "X LLP is authorised and regulated by...".
317	const SUFFIX_ALT = V.LEGAL_ENTITY_SUFFIXES
318	  .map((x) => x.replace(/[.*+?^${}()|[\]\\]/g, '\\$&')).join('|');
319	const COPYRIGHT_RX = new RegExp(
320	  '(?:\\u00a9|\\(c\\)|copyright)\\s*(?:\\d{4}(?:\\s*[\\u2013-]\\s*\\d{4})?)?\\s*(?:by\\s+)?'
321	  + '([A-Za-z0-9][^|\\n]{1,119}?)'
322	  + '(?=\\s*(?:\\.(?:\\s|$)|\\||\\n|,?\\s+all\\s+rights|$))',
323	  'i'
324	);
325	
326	function parseFooterIdentity(footerText, domain) {
327	  const out = { copyright: null, regulated: null };
328	  const text = String(footerText || '');
329	  if (!text.trim()) return out;
330	
331	  const cm = COPYRIGHT_RX.exec(text);
332	  if (cm && cm[1]) {
333	    const name = tidy(cm[1]).replace(/[.,;]\s*$/, '');
334	    if (name) out.copyright = { name, quote: tidy(cm[0]).slice(0, 160) };
335	  }
336	
337	  for (const phrase of V.REGULATED_BY_PHRASES) {
338	    const esc = phrase.replace(/[.*+?^${}()|[\]\\]/g, '\\$&').replace(/\s+/g, '\\s+');
339	    const rx = new RegExp(
340	      '([A-Za-z0-9][A-Za-z0-9&\'\\u2019.,\\- ]{1,119}?)\\s+(?:is|are)\\s+' + esc + '\\b([^|\\n.]{0,80})',
341	      'i'
342	    );
343	    const m = rx.exec(text);
344	    if (m && m[1]) {
345	      // Keep only the last sentence-ish chunk before "is <phrase>".
346	      const pre = m[1].split(/[.|\n]/).pop();
347	      const name = tidy(pre).replace(/^(?:the|and)\s+/i, '');
348	      if (name) {
349	        out.regulated = { name, quote: tidy(m[0]).slice(0, 160), phrase };
350	        break;
351	      }
352	    }
353	  }
354	  // A footer name is only trusted when it carries a legal suffix or ties to the
355	  // domain; enforced by the caller via rejectReason + suffix checks.
356	  void domain;
357	  return out;
358	}
359	
360	const COMPANY_NUMBER_RX = /\b([A-Z]{2}\d{6}|\d{8})\b/g;
361	function findCompanyNumbers(bundle) {
362	  const found = new Map(); // number -> [{kind, source, quote}]
363	  const surfaces = [];
364	  const corpus = bundle && bundle.corpus ? bundle.corpus : {};
365	  if (typeof corpus.footerText === 'string' && corpus.footerText.trim()) {
366	    surfaces.push({ kind: 'footer', source: 'corpus.footerText', text: corpus.footerText });
367	  }
368	  for (const p of (Array.isArray(corpus.pages) ? corpus.pages : [])) {
369	    if (p && typeof p.text === 'string' && p.text.trim()) {
370	      surfaces.push({ kind: 'page', source: p.url || 'corpus.pages', text: p.text });
371	    }
372	  }
373	  for (const s of surfaces) {
374	    COMPANY_NUMBER_RX.lastIndex = 0;
375	    let m;
376	    while ((m = COMPANY_NUMBER_RX.exec(s.text)) !== null) {
377	      const idx = m.index;
378	      const windowText = s.text.slice(Math.max(0, idx - 120), idx + m[0].length + 120);
379	      const low = windowText.toLowerCase();
380	      const inContext = V.COMPANY_NUMBER_CONTEXT_TERMS.some((t) => low.indexOf(t.toLowerCase()) !== -1);
381	      if (!inContext) continue; // a bare 8-digit string with no context is not a company number
382	      const num = m[1].toUpperCase();
383	      if (!found.has(num)) found.set(num, []);
384	      found.get(num).push({ kind: s.kind, source: s.source, quote: tidy(windowText).slice(0, 160) });
385	    }
386	  }
387	  return found;
388	}
389	
390	function formatOffice(v) {
391	  if (typeof v === 'string') return tidy(v) || null;
392	  if (v && typeof v === 'object') {
393	    const parts = [
394	      v.care_of, v.po_box, v.premises, v.address_line_1, v.address_line_2,
395	      v.locality, v.region, v.postal_code, v.country,
396	    ].map((x) => (typeof x === 'string' ? x.trim() : '')).filter(Boolean);
397	    return parts.length ? parts.join(', ') : null;
398	  }
399	  return null;
400	}
401	
402	// Flexible reader for the pre-fetched Companies House row (field names vary by fetcher).
403	function readCompaniesHouseRow(registers) {
404	  const row = registers && typeof registers === 'object' ? registers.companiesHouse : null;
405	  if (!row || typeof row !== 'object') return null;
406	  const name = tidy(row.legal_name || row.company_name || row.title || row.name || '');
407	  const numRaw = row.company_number || row.companyNumber || row.number || '';
408	  const number = tidy(String(numRaw)).toUpperCase() || null;
409	  const office = formatOffice(
410	    row.registered_office != null ? row.registered_office
411	      : (row.registered_office_address != null ? row.registered_office_address
412	        : row.registeredOffice)
413	  );
414	  if (!name && !number) return null;
415	  return { name: name || null, number, office };
416	}
417	
418	// ---------------------------------------------------------------------------------
419	// Slug: kebab-case of the resolved display_name. NEVER the page title (caution C-003).
420	// ---------------------------------------------------------------------------------
421	const SLUG_RX = /^[a-z0-9]+(?:-[a-z0-9]+)*$/;
422	function kebab(s) {
423	  const out = tidy(s).toLowerCase()
424	    .replace(/&/g, ' and ')
425	    .normalize('NFKD')
426	    .replace(/[\u0300-\u036f]/g, '')
427	    .replace(/['’]/g, '')
428	    .replace(/[^a-z0-9]+/g, '-')
429	    .replace(/^-+|-+$/g, '');
430	  return SLUG_RX.test(out) ? out : null;
431	}
432	
433	// ---------------------------------------------------------------------------------
434	// The resolver
435	// ---------------------------------------------------------------------------------
436	function fact(value, confidence, evidence) {
437	  return { value: value == null ? null : value, confidence, evidence: evidence || [] };
438	}
439	function abstainFact() {
440	  return fact(null, CONFIDENCE.ABSTAIN, []);
441	}
442	
443	function sanitisePages(corpus) {
444	  const pages = corpus && Array.isArray(corpus.pages) ? corpus.pages : [];
445	  return pages
446	    .filter((p) => p && typeof p === 'object')
447	    .map((p) => ({
448	      url: typeof p.url === 'string' ? p.url : null,
449	      title: typeof p.title === 'string' ? p.title : null,
450	      text: typeof p.text === 'string' ? p.text : '',
451	      jsonLd: Array.isArray(p.jsonLd) ? p.jsonLd : [],
452	      ogSiteName: typeof p.ogSiteName === 'string' ? p.ogSiteName : null,
453	    }));
454	}
455	
456	// Homepage first: root path, else shortest path wins.
457	function orderPages(pages) {
458	  const pathLen = (u) => {
459	    if (typeof u !== 'string') return 999;
460	    try {
461	      const parsed = new URL(u.indexOf('://') === -1 ? 'https://' + u : u);
462	      const pth = parsed.pathname.replace(/\/+$/, '');
463	      return pth === '' ? 0 : pth.length;
464	    } catch (_err) {
465	      return 998; // unparseable URL: order it last, never throw (typed by position)
466	    }
467	  };
468	  return pages.slice().sort((a, b) => pathLen(a.url) - pathLen(b.url));
469	}
