473	function resolveIdentity(bundle) {
474	  const notes = [];
475	  const rejected = [];
476	  if (VOCABULARY_SOURCE !== 'facts/vocabulary.js') {
477	    notes.push('vocabulary: facts/vocabulary.js absent at load time; frozen inline fallback in use (migrate when the vocabulary module lands)');
478	  }
479	
480	  const malformed = !bundle || typeof bundle !== 'object'
481	    || !bundle.corpus || typeof bundle.corpus !== 'object';
482	  const domain = !malformed && typeof bundle.domain === 'string' ? tidy(bundle.domain) : '';
483	
484	  if (malformed || (!domain && sanitisePages(bundle.corpus).length === 0)) {
485	    notes.push('malformed_evidence_bundle: expected {corpus:{pages:[]}, registers, domain}; abstaining on every field');
486	    return {
487	      fact: 'identity',
488	      domain: domain || null,
489	      display_name: abstainFact(),
490	      legal_name: abstainFact(),
491	      company_number: abstainFact(),
492	      registered_office: abstainFact(),
493	      slug: abstainFact(),
494	      rejected,
495	      notes,
496	      vocabulary_source: VOCABULARY_SOURCE,
497	    };
498	  }
499	
500	  const pages = orderPages(sanitisePages(bundle.corpus));
501	  const footerText = typeof bundle.corpus.footerText === 'string' ? bundle.corpus.footerText : '';
502	  const onPageNumbers = findCompanyNumbers(bundle);
503	
504	  // --------------------------- on-page candidates (rungs 2-5) ---------------------
505	  const accepted = []; // {value, rung, kind, source, quote?}
506	  const consider = (value, rung, source, quote) => {
507	    const reason = rejectReason(value, domain);
508	    if (reason) {
509	      rejected.push({ value: tidy(value), rung, reason });
510	      return null;
511	    }
512	    const entry = { value: tidy(value), rung, source: source || null, quote: quote || null };
513	    accepted.push(entry);
514	    return entry;
515	  };
516	
517	  const jsonLdOrgs = collectJsonLdOrgs(pages);
518	  const jsonLdLegalNames = [];
519	  for (const org of jsonLdOrgs) {
520	    consider(org.name, 'jsonld', org.url, null);
521	    if (org.legalName) jsonLdLegalNames.push({ value: tidy(org.legalName), url: org.url });
522	  }
523	
524	  for (const p of pages) {
525	    if (p.ogSiteName) {
526	      consider(p.ogSiteName, 'og_site_name', p.url, null);
527	      break; // one ogSiteName is enough; templates repeat it
528	    }
529	  }
530	
531	  const footer = parseFooterIdentity(footerText, domain);
532	  if (footer.copyright) consider(footer.copyright.name, 'footer', 'corpus.footerText', footer.copyright.quote);
533	  if (footer.regulated) consider(footer.regulated.name, 'footer', 'corpus.footerText', footer.regulated.quote);
534	
535	  const homeTitle = (pages.find((p) => p.title) || {}).title || null;
536	  for (const c of titleCandidates(homeTitle, domain)) {
537	    if (consider(c, 'title', 'corpus.pages[].title', homeTitle ? tidy(homeTitle).slice(0, 160) : null)) break;
538	    // keep rejecting until one sticks or the pool is exhausted
539	  }
540	
541	  // Group accepted candidates by normalised name to count corroboration.
542	  const groups = new Map();
543	  for (const e of accepted) {
544	    const key = normName(e.value);
545	    if (!key) continue;
546	    if (!groups.has(key)) groups.set(key, []);
547	    groups.get(key).push(e);
548	  }
549	
550	  // ------------------------------- register rung ---------------------------------
551	  const reg = readCompaniesHouseRow(bundle.registers);
552	  let regAttachment = 'none'; // 'register' | 'weak' | 'none'
553	  const regEvidence = [];
554	  if (reg && reg.name) {
555	    const regReject = rejectReason(reg.name, domain, { fromRegister: true });
556	    if (regReject) {
557	      rejected.push({ value: reg.name, rung: 'register', reason: regReject });
558	      notes.push('companiesHouse: register row rejected (' + regReject + '); legal fields abstain');
559	    } else {
560	      const regNorm = normName(reg.name);
561	      const numberOnPage = Boolean(reg.number && onPageNumbers.has(reg.number));
562	      const nameOnPage = (regNorm && groups.has(regNorm))
563	        || (regNorm.length >= 6 && (
564	          compact(footerText).indexOf(compact(stripLegalSuffixes(reg.name))) !== -1
565	          || pages.some((p) => compact(p.text).indexOf(compact(stripLegalSuffixes(reg.name))) !== -1)
566	        ));
567	      regEvidence.push({ kind: 'register', source: 'registers.companiesHouse', quote: reg.name });
568	      if (numberOnPage) {
569	        regEvidence.push(Object.assign({}, onPageNumbers.get(reg.number)[0]));
570	      }
571	      if (nameOnPage && regNorm && groups.has(regNorm)) {
572	        const first = groups.get(regNorm)[0];
573	        regEvidence.push({ kind: first.rung, source: first.source, quote: first.quote || first.value });
574	      }
575	      if (numberOnPage || nameOnPage) {
576	        regAttachment = 'register';
577	      } else if (sharesTokenWithDomain(reg.name, domain)) {
578	        regAttachment = 'weak';
579	        notes.push('companiesHouse: register row ties to the domain but no on-page identifier corroborates it; attached at weak confidence only');
580	      } else {
581	        regAttachment = 'none';
582	        notes.push('companiesHouse: register row shares no token with the domain and nothing on-page corroborates it; row ignored (a wrong register match is worse than none)');
583	      }
584	    }
585	  }
586	
587	  // ------------------------------- display_name ----------------------------------
588	  let displayName = abstainFact();
589	  if (regAttachment === 'register') {
590	    displayName = fact(titleCase(reg.name), CONFIDENCE.REGISTER, regEvidence.slice(0, 4));
591	  } else {
592	    let winner = null;
593	    for (const rung of RUNG_ORDER) {
594	      winner = accepted.find((e) => e.rung === rung) || null;
595	      if (winner) break;
596	    }
597	    if (winner) {
598	      const group = groups.get(normName(winner.value)) || [winner];
599	      const distinctRungs = new Set(group.map((e) => e.rung));
600	      const conf = distinctRungs.size >= 2 ? CONFIDENCE.CORROBORATED : CONFIDENCE.WEAK;
601	      const evidence = group.slice(0, 4).map((e) => ({
602	        kind: e.rung, source: e.source, quote: e.quote || e.value,
603	      }));
604	      displayName = fact(winner.value, conf, evidence);
605	    } else if (regAttachment === 'weak') {
606	      displayName = fact(titleCase(reg.name), CONFIDENCE.WEAK, regEvidence.slice(0, 2));
607	    } else {
608	      const stem = domainStem(domain);
609	      if (stem) {
610	        const cleaned = titleCase(stem.replace(/[-_]+/g, ' '));
611	        displayName = fact(cleaned, CONFIDENCE.WEAK, [{ kind: 'domain', source: domain }]);
612	        notes.push('display_name fell through to the domain stem: no register, schema.org, ogSiteName, footer or usable title candidate survived rejection');
613	      } else {
614	        notes.push('display_name: no candidate survived rejection and no domain stem available; abstaining');
615	      }
616	    }
617	  }
618	
619	  // -------------------------------- legal_name -----------------------------------
620	  let legalName = abstainFact();
621	  if ((regAttachment === 'register' || regAttachment === 'weak') && reg.name) {
622	    const conf = regAttachment === 'register' ? CONFIDENCE.REGISTER : CONFIDENCE.WEAK;
623	    legalName = fact(reg.name, conf, regEvidence.slice(0, 3));
624	  } else {
625	    const suffixed = (s) => SUFFIX_TEST_RX.test(String(s || ''));
626	    const candidates = [];
627	    for (const ln of jsonLdLegalNames) {
628	      if (!rejectReason(ln.value, domain)) candidates.push({ value: ln.value, kind: 'jsonld', source: ln.url });
629	    }
630	    for (const f of [footer.copyright, footer.regulated]) {
631	      if (f && suffixed(f.name) && !rejectReason(f.name, domain)) {
632	        candidates.push({ value: f.name, kind: 'footer', source: 'corpus.footerText', quote: f.quote });
633	      }
634	    }
635	    if (candidates.length) {
636	      const byNorm = new Map();
637	      for (const c of candidates) {
638	        const k = normName(c.value);
639	        if (!byNorm.has(k)) byNorm.set(k, []);
640	        byNorm.get(k).push(c);
641	      }
642	      const bestKey = Array.from(byNorm.keys()).sort(
643	        (a, b) => byNorm.get(b).length - byNorm.get(a).length
644	      )[0];
645	      const grp = byNorm.get(bestKey);
646	      const distinctKinds = new Set(grp.map((c) => c.kind));
647	      legalName = fact(
648	        grp[0].value,
649	        distinctKinds.size >= 2 ? CONFIDENCE.CORROBORATED : CONFIDENCE.WEAK,
650	        grp.slice(0, 3).map((c) => ({ kind: c.kind, source: c.source, quote: c.quote || c.value }))
651	      );
652	    }
653	  }
654	
655	  // ------------------------------ company_number ---------------------------------
656	  let companyNumber = abstainFact();
657	  if (regAttachment === 'register' && reg.number) {
658	    companyNumber = fact(reg.number, CONFIDENCE.REGISTER, regEvidence.slice(0, 3));
659	  } else if (regAttachment === 'weak' && reg.number) {
660	    companyNumber = fact(reg.number, CONFIDENCE.WEAK, regEvidence.slice(0, 2));
661	  } else {
662	    const distinct = Array.from(onPageNumbers.keys());
663	    if (distinct.length === 1) {
664	      const sightings = onPageNumbers.get(distinct[0]);
665	      const distinctSources = new Set(sightings.map((s) => s.source));
666	      companyNumber = fact(
667	        distinct[0],
668	        distinctSources.size >= 2 ? CONFIDENCE.CORROBORATED : CONFIDENCE.WEAK,
669	        sightings.slice(0, 3)
670	      );
671	    } else if (distinct.length > 1) {
672	      notes.push('company_number: ' + distinct.length + ' distinct contextual numbers found on-page with no register to arbitrate; abstaining (conflict is not evidence)');
673	    }
674	  }
675	
676	  // ----------------------------- registered_office -------------------------------
677	  let registeredOffice = abstainFact();
678	  if ((regAttachment === 'register' || regAttachment === 'weak') && reg.office) {
679	    registeredOffice = fact(
680	      reg.office,
681	      regAttachment === 'register' ? CONFIDENCE.REGISTER : CONFIDENCE.WEAK,
682	      [{ kind: 'register', source: 'registers.companiesHouse', quote: reg.office }]
683	    );
684	  }
685	
686	  // ----------------------------------- slug --------------------------------------
687	  let slug = abstainFact();
688	  if (displayName.value) {
689	    const s = kebab(displayName.value);
690	    if (s) {
691	      slug = fact(s, displayName.confidence, [{ kind: 'derived', source: 'display_name' }]);
692	    } else {
693	      notes.push('slug: display_name did not kebab to a clean slug; abstaining rather than shipping residue');
694	    }
695	  }
696	
697	  return {
698	    fact: 'identity',
699	    domain: domain || null,
700	    display_name: displayName,
701	    legal_name: legalName,
702	    company_number: companyNumber,
703	    registered_office: registeredOffice,
704	    slug,
705	    rejected,
706	    notes,
707	    vocabulary_source: VOCABULARY_SOURCE,
708	  };
709	}
