2	// CALIBRATION FIXTURE (known-bad INPUT, self-testing dialect) for facts/jurisdiction.js.
3	//
4	// This is not planted bad code: it is the corpus of ADVERSARIAL INPUTS that destroyed the old
5	// engine, and the single door must refuse every trap on every run. Primary class: the Mills &
6	// Reeve ghost-US footer (caution.md C-009), where an unanchored /incorporated in/ judged six of
7	// seven real UK/EU/UAE law-firm footers "established in the United States" and served a UK firm
8	// US ABA rules. Also seeded: the fichtelegal DIFC-Courts advocacy class (C-010), the
9	// service-offer establishment class (C-011), the Tier-C-never-binds rule, the empty-register
10	// non-match (C-004) and the confident-default-jurisdiction disease (C-006).
11	//
12	// DIALECT (earn-your-zero polarity, matching eval/calibration-known-bad/run.js semantics):
13	//   calibrate() returns a findings ARRAY. One finding is emitted per trap the module CORRECTLY
14	//   refuses. If ANY trap is missed (the module binds the poison jurisdiction), calibrate()
15	//   returns an EMPTY array and writes the misses to stderr, so a runner that requires non-empty
16	//   findings fails exactly when the module has regressed. run.js may adopt this fixture with an
17	//   internal entry: require the fixture, call calibrate(), judge findings.length.
18	//   Standalone: `node eval/calibration-known-bad/fixtures/p1-jurisdiction-anchored-nexus.js`
19	//   exits 1 on any miss.
20	
21	const path = require('path');
22	const { resolveJurisdiction } = require(path.resolve(__dirname, '..', '..', '..', 'facts', 'jurisdiction.js'));
23	
24	// The six real footers from the old estate's nexus-anchoring corpus, verbatim classes.
25	const FOOTERS = Object.freeze({
26	  'mills-reeve (UK)': 'Mills & Reeve LLP is a limited liability partnership incorporated in England and Wales. Company number OC326013. Our office in Cambridge.',
27	  'birketts (UK)': 'Birketts LLP is a limited liability partnership registered in England and Wales. SRA Registration No: 441849.',
28	  'russell-cooke (UK)': 'Russell-Cooke LLP is incorporated in England and Wales, registered office 2 Putney Hill, London.',
29	  'freeths (UK)': 'Freeths LLP, incorporated in England and Wales with registered number OC304688.',
30	  'al-tamimi (AE)': 'Al Tamimi & Company. Our offices in Dubai and Abu Dhabi. We advise clients on US LLC formation and Delaware incorporation.',
31	  'franklin (FR)': 'Cabinet Franklin, based in France. Our office in Paris. Inscrit au Barreau de Paris.',
32	});
33	
34	function bundleOf(footer, pageText, domain) {
35	  return {
36	    corpus: {
37	      pages: pageText ? [{ url: 'https://' + (domain || 'example.com') + '/', title: 'Home', text: pageText, jsonLd: [] }] : [],
38	      footerText: footer || '',
39	    },
40	    registers: {},
41	    domain: domain || 'example.com',
42	  };
43	}
44	
45	const TRIALS = [];
46	for (const [firm, footer] of Object.entries(FOOTERS)) {
47	  TRIALS.push({
48	    name: 'ghost-us:' + firm,
49	    // the nav-menu mention that fed the old Tier-C leak rides along on every trial
50	    bundle: bundleOf(footer, 'M&R Global | USA and Canada', 'example.com'),
51	    mustNotBind: ['US'],
52	    detail: 'a non-US footer must never bind the United States (C-009)',
53	  });
54	}
55	TRIALS.push({
56	  name: 'difc-courts-advocacy (fichtelegal class)',
57	  bundle: bundleOf(
58	    'Our litigators are registered with the DIFC Courts and appear regularly before the DIFC Courts. Based in Dubai.',
59	    'Call us on +971 4 123 4567. Consultations from AED 500.',
60	    'example.com'
61	  ),
62	  mustNotBind: [],
63	  mustNotSubJurisdiction: ['DIFC', 'ADGM'],
64	  detail: 'court advocacy is not free-zone establishment; no displacement of the federal regime (C-010)',
65	});
66	TRIALS.push({
67	  name: 'service-offer-establishment',
68	  bundle: bundleOf('', 'We help you set up in the DIFC. Company formation services for the UAE and the United Kingdom.', 'example.com'),
69	  mustNotBind: ['UK', 'AE'],
70	  mustNotSubJurisdiction: ['DIFC', 'ADGM'],
71	  detail: 'selling establishment services proves nothing about the seller (C-011)',
72	});
73	TRIALS.push({
74	  name: 'tier-c-never-binds',
75	  bundle: bundleOf('', 'We advise clients across the Middle East and in Dubai. Our partners are admitted to the New York bar. Case study: a client in Germany.', 'example.com'),
76	  mustNotBind: ['AE', 'US', 'DE', 'EU'],
77	  mustAbstain: true,
78	  detail: 'marketing prose, bar admissions and case studies never attach law in any combination',
79	});
80	TRIALS.push({
81	  name: 'empty-register-non-match',
82	  bundle: { corpus: { pages: [], footerText: '' }, registers: { companiesHouse: {} }, domain: 'example.com' },
83	  mustNotBind: ['UK'],
84	  mustAbstain: true,
85	  detail: 'a bare non-empty register response with no name and no identifier is not a match (C-004)',
86	});
87	TRIALS.push({
88	  name: 'confident-default',
89	  bundle: { corpus: { pages: [], footerText: '' }, registers: {}, domain: 'example.com' },
90	  mustNotBind: ['UK', 'US', 'EU', 'AE', 'IE'],
91	  mustAbstain: true,
92	  detail: 'no evidence means abstention, never a default jurisdiction (C-006)',
93	});
94	
95	function runTrials() {
96	  const misses = [];
97	  for (const trial of TRIALS) {
98	    const out = resolveJurisdiction(trial.bundle);
99	    const boundCodes = out.bound.map((b) => b.jurisdiction);
100	    for (const code of trial.mustNotBind || []) {
101	      if (boundCodes.includes(code)) {
102	        misses.push(trial.name + ': bound the poison jurisdiction "' + code + '" (' + trial.detail + ')');
103	      }
104	    }
105	    for (const code of trial.mustNotSubJurisdiction || []) {
106	      if (out.sub_jurisdictions.some((s) => s.code === code)) {
107	        misses.push(trial.name + ': attached forbidden sub-jurisdiction "' + code + '" (' + trial.detail + ')');
108	      }
109	    }
110	    if (trial.mustAbstain && !out.abstained) {
111	      misses.push(trial.name + ': expected abstention, got bound [' + boundCodes.join(', ') + ']');
112	    }
113	  }
114	  return misses;
115	}
116	
117	function calibrate() {
118	  const misses = runTrials();
119	  if (misses.length > 0) {
120	    for (const m of misses) console.error('MISSED TRAP ' + m);
121	    return []; // empty findings = the gate has not earned its zero; a strict runner fails
122	  }
123	  return TRIALS.map((trial) => ({
124	    file: __filename,
125	    rule: 'p1-jurisdiction-anchored-nexus',
126	    message: 'trap caught: ' + trial.name + ' (' + trial.detail + ')',
127	  }));
128	}
129	
130	module.exports = { FOOTERS, TRIALS, bundleOf, runTrials, calibrate };
131	
132	if (require.main === module) {
133	  const misses = runTrials();
134	  if (misses.length > 0) {
135	    console.error('p1-jurisdiction-anchored-nexus: ' + misses.length + ' trap(s) MISSED');
136	    process.exit(1);
137	  }
138	  console.log(JSON.stringify({ checker: 'p1-jurisdiction-anchored-nexus', findings: calibrate() }));
139	  process.exit(0);
140	}
