39	// abstainedFacts(facts) -> true when identity/jurisdiction/sector ALL abstained (no confident value).
40	// Deliberately does not check capabilities: RT-D's own expected text names identity/sector/jurisdiction
41	// only ("no confident sector/identity/jurisdiction"), so this is not a partial check, it is the full
42	// stated contract.
43	function abstainedFacts(facts) {
44	  const idAbstained = !facts.identity || !facts.identity.legal_name || facts.identity.legal_name.value == null;
45	  const jurAbstained = !facts.jurisdiction || !Array.isArray(facts.jurisdiction.bound) || facts.jurisdiction.bound.length === 0;
46	  const secAbstained = !facts.sector || facts.sector.value == null;
47	  return idAbstained && jurAbstained && secAbstained;
