50	// buildChallengeHtml(fetchInput) -> a minimal HTML document carrying the fixture's split title/
51	// body_text fields, so extract.js's real pageContentClass() (which extracts its OWN title from HTML)
52	// sees a genuine <title> rather than an empty one.
53	function buildChallengeHtml(fetchInput) {
54	  return '<html><head><title>' + (fetchInput.title || '') + '</title></head><body>' + (fetchInput.body_text || '') + '</body></html>';
